`def max_profit_kadane():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    N = int(data[0])
    K = int(data[1])
    arr = list(map(int, data[2:]))

    # Compute maximum subarray sum ending at each index (Kadane's algorithm).
    best = [0] * N
    best[0] = arr[0]
    for i in range(1, N):
        best[i] = max(arr[i], best[i - 1] + arr[i])

    # Compute the sum for the first window of size K.
    window_sum = sum(arr[:K])
    ans = window_sum

    # Slide the window and update the maximum profit.
    for i in range(K, N):
        window_sum += arr[i] - arr[i - K]
        candidate = window_sum
        if i - K &gt;= 0:
            candidate += max(0, best[i - K])
        ans = max(ans, candidate)
    print(ans)

if __name__ == '__main__':
    max_profit_kadane()
